lessons.starter_code:
# 异常处理
def divide_mana(a, b):
    try:
        result = a / b
        print(f"魔力分配: {a} / {b} = {result}")
        return result
    except ZeroDivisionError:
        print("⚠️ 错误：不能除以零！")
        return 0
    except Exception as e:
        print(f"⚠️ 未知错误: {e}")
        return 0

# 测试
divide_mana(100, 5)
divide_mana(50, 2)
divide_mana(100, 0)  # 这会触发异常

def cast_spell(spell_name, power):
    try:
        if power < 0:
            raise ValueError("魔力值不能为负数！")
        print(f"施展 {spell_name}，消耗 {power} 魔力")
    except ValueError as e:
        print(f"⚠️ 施法失败: {e}")

cast_spell("火球术", 30)
cast_spell("冰霜术", -10)  # 这会触发自定义异常

